create table dirkspzm32.edi_vda4987_engine (
    document_id    varchar2(32 char) not null enable,
    article_id     varchar2(32 char) not null enable,
    pos            number(4, 0) not null enable,
    engine_number1 varchar2(32 char),
    engine_number2 varchar2(32 char),
    engine_number3 varchar2(32 char),
    engine_number4 varchar2(32 char),
    engine_number5 varchar2(32 char)
);

alter table dirkspzm32.edi_vda4987_engine
    add constraint pk_edi_vda4987_engine primary key ( article_id,
                                                       pos )
        using index enable;


